# -----------------------------
# TOTP (RFC 6238) minimal implementation
# -----------------------------
def _b32decode_nopad(s: str) -> bytes:
    s = s.strip().upper().replace(" ", "")
    pad = "=" * ((8 - (len(s) % 8)) % 8)
    return base64.b32decode(s + pad, casefold=True)

def totp(secret_b32: str, timestep: int = 30, digits: int = 6, t: int | None = None) -> str:
    if t is None:
        t = int(time.time())
    counter = int(t // timestep)
    key = _b32decode_nopad(secret_b32)
    msg = counter.to_bytes(8, "big")
    digest = hmac.new(key, msg, hashlib.sha1).digest()
    offset = digest[-1] & 0x0F
    code_int = int.from_bytes(digest[offset:offset + 4], "big") & 0x7FFFFFFF
    code = code_int % (10 ** digits)
    return str(code).zfill(digits)

def verify_totp(secret_b32: str, code: str, window: int = 1, timestep: int = 30, digits: int = 6) -> bool:
    code = (code or "").strip()
    if not code.isdigit() or len(code) != digits:
        return False
    now = int(time.time())
    for w in range(-window, window + 1):
        if hmac.compare_digest(totp(secret_b32, timestep=timestep, digits=digits, t=now + w * timestep), code):
            return True
    return False

