def _json_error(message: str, status: int):
    return jsonify({"ok": False, "error": message}), status

@app.route("/api/login", methods=["POST"])
def api_login():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "")
    password = data.get("password", "")
    otp = data.get("otp")

    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return _json_error("invalid_credentials", 401)

    if user.get("mfa_enabled"):
        if not otp:
            return jsonify({"ok": False, "mfa_required": True}), 401
        if not user.get("mfa_secret") or not verify_totp(user["mfa_secret"], str(otp)):
            return _json_error("invalid_otp", 401)

    token = secrets.token_urlsafe(32)
    return jsonify({"ok": True, "token": token, "user": {"id": user["id"], "username": user["username"]}})

@app.route("/api/direct-login", methods=["POST"])
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "")
    password = data.get("password", "")
